import { notFound } from 'next/navigation';
import Image from 'next/image';
import { cooperatives } from '../../../data/mockData';
import ZoneProductGrid from '../../../components/ZoneProductGrid';
import ZoneCooperativesCards from '../../../components/ZoneCooperativesCards';
import ZoneNavigator from '../../../components/ZoneNavigator';
import { Flame, Package, Store } from 'lucide-react';

type ZonePageProps = {
  params: Promise<{ slug: string }>;
};

const zoneImages: Record<string, string> = {
  Errachidia:
    'https://images.pexels.com/photos/9399898/pexels-photo-9399898.jpeg?auto=compress&cs=tinysrgb&w=1600',
  Tinghir:
    'https://images.pexels.com/photos/971360/pexels-photo-971360.jpeg?auto=compress&cs=tinysrgb&w=1600',
  Midelt:
    'https://images.pexels.com/photos/27429847/pexels-photo-27429847.jpeg?auto=compress&cs=tinysrgb&w=1600',
  Zagora:
    'https://images.pexels.com/photos/2662116/pexels-photo-2662116.jpeg?auto=compress&cs=tinysrgb&w=1600',
};

function slugifyZone(zone: string) {
  return zone
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim()
    .replace(/\s+/g, '-');
}

export function generateStaticParams() {
  const zones = Array.from(new Set(cooperatives.map((c) => c.zone)));
  return zones.map((zone) => ({ slug: slugifyZone(zone) }));
}

export default async function ZonePage({ params }: ZonePageProps) {
  const { slug } = await params;
  const zone = Array.from(new Set(cooperatives.map((c) => c.zone))).find(
    (z) => slugifyZone(z) === slug,
  );

  if (!zone) notFound();

  const zoneCooperatives = cooperatives.filter((c) => c.zone === zone);
  const allProducts = zoneCooperatives.flatMap((coop) =>
    coop.products.map((product) => ({
      ...product,
      cooperativeSlug: coop.slug,
      category: coop.category,
      cooperativeName: (() => {
        const short = coop.name.replace(/^Coopérative\s+/i, '');
        return short.length > 20 ? `${short.slice(0, 18)}…` : short;
      })(),
    })),
  );
  // Best-sellers = premier produit de chaque coopérative de la zone
  const bestSellerProducts = zoneCooperatives.flatMap((coop) => {
    const firstProduct = coop.products[0];
    if (!firstProduct) return [];
    return [{
      ...firstProduct,
      cooperativeSlug: coop.slug,
      category: coop.category,
      cooperativeName: (() => {
        const short = coop.name.replace(/^Coopérative\s+/i, '');
        return short.length > 20 ? `${short.slice(0, 18)}…` : short;
      })(),
    }];
  });

  const heroImage = zoneImages[zone] ?? zoneCooperatives[0]?.coverImage;
  const totalProducts = allProducts.length;
  const categories = Array.from(new Set(bestSellerProducts.map((p) => p.category)));

  return (
    <main className="min-h-screen">
      {/* Hero */}
      <section className="relative h-[35vh] min-h-[240px] w-full overflow-hidden rounded-b-3xl md:h-[42vh] md:min-h-[320px]">
        <Image
          src={heroImage}
          alt={`Les trésors de ${zone}`}
          fill
          sizes="100vw"
          className="object-cover"
          priority
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/30 to-black/10" />
        <div className="absolute inset-0 flex flex-col justify-end p-6 md:p-10">
          <h1 className="text-3xl font-bold text-white drop-shadow-lg md:text-4xl lg:text-5xl">
            Les Trésors de {zone}
          </h1>
          <p className="mt-2 max-w-2xl text-white/90 md:text-lg">
            Découvrez les coopératives et produits de la région
          </p>
        </div>
      </section>

      <div className="mx-auto max-w-6xl px-4 py-8 md:px-6">
        {/* Stats box */}
        <section className="mb-8">
          <div className="rounded-2xl border border-white/50 bg-white/90 p-6 shadow-soft backdrop-blur-sm">
            <div className="flex flex-wrap items-center justify-between gap-6">
              <div className="flex items-center gap-4">
                <div className="flex h-14 w-14 items-center justify-center rounded-2xl bg-terracotta/15 text-terracotta">
                  <Store size={28} />
                </div>
                <div>
                  <p className="text-2xl font-bold text-palmier">
                    {zoneCooperatives.length} coopérative{zoneCooperatives.length > 1 ? 's' : ''}
                  </p>
                  <p className="text-sm text-palmier/70">dans la zone {zone}</p>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <div className="flex h-14 w-14 items-center justify-center rounded-2xl bg-palmier/15 text-palmier">
                  <Package size={28} />
                </div>
                <div>
                  <p className="text-2xl font-bold text-palmier">{totalProducts} produits</p>
                  <p className="text-sm text-palmier/70">
                    {bestSellerProducts.length} best-sellers
                  </p>
                </div>
              </div>
              <div className="hidden items-center gap-2 sm:flex">
                {categories.map((cat) => (
                  <span
                    key={cat}
                    className="rounded-full bg-sage/20 px-3 py-1 text-sm font-medium text-palmier"
                  >
                    {cat}
                  </span>
                ))}
              </div>
            </div>
          </div>
        </section>

        {/* Cooperatives */}
        <section className="mb-12">
          <div className="mb-6 flex items-center justify-between">
            <h2 className="text-xl font-semibold text-palmier">Coopératives de la zone</h2>
            <span className="text-sm text-palmier/70">
              {zoneCooperatives.length} coopérative{zoneCooperatives.length > 1 ? 's' : ''}
            </span>
          </div>
          <ZoneCooperativesCards cooperatives={zoneCooperatives} />
        </section>

        {/* Best-sellers des coopératives de la zone */}
        <section>
          <div className="mb-6 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Flame size={22} className="text-terracotta" />
              <h2 className="text-xl font-semibold text-palmier">
                Best-sellers des coopératives
              </h2>
            </div>
            <span className="text-sm text-palmier/70">
              {bestSellerProducts.length} produit{bestSellerProducts.length > 1 ? 's' : ''} phare
              {bestSellerProducts.length > 1 ? 's' : ''}
            </span>
          </div>
          <ZoneProductGrid products={bestSellerProducts} allBestSellers />
        </section>

        {/* Explore other zones */}
        <section className="mt-16">
          <h2 className="mb-6 text-xl font-semibold text-palmier">
            Explorer d&apos;autres zones
          </h2>
          <ZoneNavigator />
        </section>
      </div>
    </main>
  );
}
